package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    String expectedCurrencyCode = "USD";

    // Use reflection to create instance since constructor might be missing in source snippet
    Class<?> clazz = Class.forName("com.google.gson.examples.android.model.LineItem");
    java.lang.reflect.Constructor<?> constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance("TestItem", 5, 1000L, expectedCurrencyCode);

    java.lang.reflect.Method getCurrencyCodeMethod = clazz.getDeclaredMethod("getCurrencyCode");
    getCurrencyCodeMethod.setAccessible(true);
    String actualCurrencyCode = (String) getCurrencyCodeMethod.invoke(lineItem);

    assertEquals(expectedCurrencyCode, actualCurrencyCode);
  }
}
